import type { CareerQuestion } from "./rrt-questions";

export const psychotherapistQuestionsBatch3: CareerQuestion[] = [
  { id: "rp-601", stem: "A therapist using Interpersonal Therapy (IPT) for depression would focus primarily on:", options: ["Current interpersonal disputes, role transitions, grief, or interpersonal deficits","Early childhood memories and unconscious conflicts","Automatic negative thoughts and cognitive distortions","Behavioral reinforcement schedules"], correctIndex: 0, rationale: "IPT addresses four interpersonal problem areas: grief, role disputes, role transitions, and interpersonal deficits. It focuses on current relationships rather than past or cognitive patterns.", difficulty: 2, category: "Therapeutic Modalities", topic: "IPT" },
  { id: "rp-602", stem: "In Structural Family Therapy, 'joining' refers to:", options: ["The therapist's process of engaging with the family and accommodating to their style","Merging two family subsystems together","The family's decision to enter therapy","Combining individual and family sessions"], correctIndex: 0, rationale: "Joining (Minuchin) is the therapeutic process of building rapport by accommodating to the family's communication style, respecting hierarchy, and earning trust before restructuring.", difficulty: 2, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-603", stem: "A client diagnosed with antisocial personality disorder is most likely to present in therapy with:", options: ["Disregard for social norms, deceitfulness, and lack of remorse","Excessive need for admiration and grandiosity","Pervasive distrust and suspiciousness of others","Social inhibition and feelings of inadequacy"], correctIndex: 0, rationale: "ASPD features include violation of others' rights, deceitfulness, impulsivity, irritability, reckless disregard for safety, irresponsibility, and lack of remorse, with onset before age 15.", difficulty: 2, category: "Clinical Assessment", topic: "Personality Disorders" },
  { id: "rp-604", stem: "The AUDIT questionnaire is used to screen for:", options: ["Alcohol use disorders","Autism spectrum disorder","Attention deficit disorder","Acute urinary tract infections"], correctIndex: 0, rationale: "The AUDIT (Alcohol Use Disorders Identification Test) is a 10-item WHO-developed screening tool for hazardous and harmful alcohol consumption and possible dependence.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-605", stem: "Mentalization-Based Treatment (MBT) was originally developed for:", options: ["Borderline personality disorder","Generalized anxiety disorder","Obsessive-compulsive disorder","Specific phobias"], correctIndex: 0, rationale: "MBT (Bateman & Fonagy) was developed for BPD, focusing on improving the capacity to understand behavior in terms of underlying mental states (thoughts, feelings, desires).", difficulty: 3, category: "Therapeutic Modalities", topic: "MBT" },
  { id: "rp-606", stem: "A therapist working with a client who has experienced complex trauma notices the client idealizes the therapist one session and devalues them the next. This pattern is best understood as:", options: ["Splitting as a defense against relational trauma","Malingering for secondary gain","Normal fluctuations in the therapeutic alliance","Resistance to treatment engagement"], correctIndex: 0, rationale: "Splitting (viewing others as all-good or all-bad) is a primitive defense common in clients with complex trauma and BPD. It reflects early relational disruptions and difficulty integrating experiences.", difficulty: 3, category: "Clinical Assessment", topic: "Defense Mechanisms" },
  { id: "rp-607", stem: "The PHQ-2 is used as a:", options: ["Brief initial screening tool for depression with two questions about mood and anhedonia","Comprehensive depression diagnostic instrument","Personality disorder assessment","Suicide risk prediction tool"], correctIndex: 0, rationale: "The PHQ-2 asks about depressed mood and anhedonia over the past two weeks. A positive screen (score ≥3) warrants further assessment with the full PHQ-9.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-608", stem: "In trauma-informed care, the principle of 'safety' encompasses:", options: ["Physical and emotional safety for clients and staff throughout the service environment","Only physical security measures like locked doors","Safety from malpractice lawsuits","Ensuring clients never discuss distressing topics"], correctIndex: 0, rationale: "Trauma-informed safety includes physical safety (environment) and emotional safety (predictability, transparency, trustworthy staff). It applies to the entire organizational culture.", difficulty: 1, category: "Therapeutic Modalities", topic: "Trauma-Informed Care" },
  { id: "rp-609", stem: "When a therapist experiences strong emotional reactions to a client that seem disproportionate to the situation, this is most likely:", options: ["Countertransference","Empathic attunement","Professional burnout","Therapeutic neutrality"], correctIndex: 0, rationale: "Countertransference involves the therapist's emotional reactions to the client, often stemming from the therapist's own unresolved issues. Awareness and management are essential for ethical practice.", difficulty: 1, category: "Therapeutic Modalities", topic: "Psychodynamic Concepts" },
  { id: "rp-610", stem: "A client with social anxiety disorder would benefit most from which group therapy format?", options: ["Cognitive-behavioral group therapy with graded exposure exercises","Unstructured psychodynamic group analysis","Marathon encounter group","Psychoeducational lecture-based group without interaction"], correctIndex: 0, rationale: "CBT groups for social anxiety combine cognitive restructuring with graded in-group exposure exercises, providing a safe environment for practicing social skills with real-time feedback.", difficulty: 2, category: "Group Therapy", topic: "Specialized Groups" },
  { id: "rp-611", stem: "In ACT, 'experiential avoidance' refers to:", options: ["Attempts to avoid or control unwanted internal experiences such as thoughts, feelings, and sensations","Avoiding social situations due to shyness","Refusing to participate in exposure therapy","Physical avoidance of trauma-related locations"], correctIndex: 0, rationale: "Experiential avoidance is the unwillingness to remain in contact with distressing internal experiences. ACT views this as a core pathological process across many disorders.", difficulty: 2, category: "Therapeutic Modalities", topic: "ACT" },
  { id: "rp-612", stem: "Which factor most strongly predicts positive therapy outcomes across all treatment modalities?", options: ["The quality of the therapeutic alliance","The specific techniques used","The therapist's theoretical orientation","The length of treatment"], correctIndex: 0, rationale: "Research consistently shows the therapeutic alliance is the strongest predictor of outcomes, accounting for more variance than specific techniques or theoretical orientation.", difficulty: 2, category: "Therapeutic Modalities", topic: "Common Factors" },
  { id: "rp-613", stem: "A client with hoarding disorder differs from a collector primarily in that:", options: ["The hoarding causes significant distress or functional impairment","The person has more items than the average person","The items have no monetary value","The person lives alone"], correctIndex: 0, rationale: "Hoarding disorder is distinguished by clinically significant distress and/or functional impairment (inability to use living spaces). Collectors organize and display items without functional impairment.", difficulty: 2, category: "Clinical Assessment", topic: "OCD Spectrum" },
  { id: "rp-614", stem: "Strategic family therapy's concept of 'prescribing the symptom' is an example of:", options: ["Paradoxical intervention","Cognitive restructuring","Operant conditioning","Systematic desensitization"], correctIndex: 0, rationale: "Paradoxical interventions (Haley, Madanes) prescribe the symptomatic behavior to disrupt the family pattern. When the symptom becomes voluntary, it often loses its function.", difficulty: 3, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-615", stem: "The PCL-5 is a standardized self-report measure for:", options: ["PTSD symptom severity based on DSM-5 criteria","Personality disorder traits","Psychotic symptoms","Chronic pain levels"], correctIndex: 0, rationale: "The PCL-5 (PTSD Checklist for DSM-5) measures 20 PTSD symptoms corresponding to DSM-5 criteria. It is used for screening, diagnosis, and monitoring treatment progress.", difficulty: 2, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-616", stem: "A therapist using the 'downward arrow' technique is:", options: ["Exploring the deeper meaning and core beliefs underlying a surface-level automatic thought","Helping a client relax by imagining descending stairs","Teaching progressive muscle relaxation","Guiding the client through grief stages"], correctIndex: 0, rationale: "The downward arrow technique follows automatic thoughts to their root by repeatedly asking 'What would that mean?' until core beliefs are identified (e.g., 'I am unlovable').", difficulty: 3, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-617", stem: "When working with a client who has experienced racial trauma, the therapist should:", options: ["Validate the client's experiences and acknowledge the reality of systemic racism","Encourage the client to forgive and move on quickly","Focus only on individual pathology without considering social context","Minimize racial experiences to maintain therapeutic neutrality"], correctIndex: 0, rationale: "Racial trauma requires validation, acknowledgment of systemic factors, and culturally responsive treatment. Minimizing or individualizing systemic experiences can re-traumatize the client.", difficulty: 2, category: "Cultural Competence", topic: "Racial Trauma" },
  { id: "rp-618", stem: "In group therapy, 'scapegoating' occurs when:", options: ["The group directs hostility toward one member, projecting unwanted qualities onto them","A member takes on a leadership role","The therapist singles out a member for praise","Two members form an exclusive alliance"], correctIndex: 0, rationale: "Scapegoating is a destructive group process where collective anxiety or hostility is displaced onto one member. The therapist must intervene to protect the member and explore the group dynamic.", difficulty: 2, category: "Group Therapy", topic: "Group Dynamics" },
  { id: "rp-619", stem: "Acceptance and Commitment Therapy identifies six core processes of psychological flexibility. Which is NOT one of them?", options: ["Cognitive restructuring","Acceptance","Defusion","Values"], correctIndex: 0, rationale: "ACT's six core processes are: acceptance, defusion, present moment awareness, self-as-context, values, and committed action. Cognitive restructuring is a CBT technique, not an ACT process.", difficulty: 3, category: "Therapeutic Modalities", topic: "ACT" },
  { id: "rp-620", stem: "A client presents with recurrent episodes of binge eating followed by compensatory purging. Between episodes, the client maintains a normal weight. The most appropriate diagnosis is:", options: ["Bulimia nervosa","Anorexia nervosa, binge-eating/purging type","Binge eating disorder","Other specified feeding or eating disorder"], correctIndex: 0, rationale: "Bulimia nervosa features recurrent binge eating with compensatory behaviors (purging, fasting, excessive exercise) at normal or above-normal weight. AN requires significantly low weight.", difficulty: 2, category: "Clinical Assessment", topic: "Eating Disorders" },
  { id: "rp-621", stem: "The concept of 'parallel process' in clinical supervision refers to:", options: ["Dynamics from the therapy relationship being unconsciously replicated in the supervisory relationship","Running two therapy sessions simultaneously","Supervising two trainees at the same time","Using the same treatment manual across different clients"], correctIndex: 0, rationale: "Parallel process occurs when the supervisee unconsciously enacts with the supervisor the same dynamics occurring between the supervisee and their client, providing valuable clinical information.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Supervision" },
  { id: "rp-622", stem: "A client with PTSD avoids all trauma-related stimuli and reports emotional numbing. According to the DSM-5, these belong to which symptom cluster?", options: ["Avoidance","Intrusion","Negative alterations in cognition and mood","Alterations in arousal and reactivity"], correctIndex: 0, rationale: "DSM-5 PTSD Cluster C (Avoidance) includes avoiding trauma-related thoughts/feelings and external reminders. Emotional numbing was moved to Cluster D (Negative cognitions and mood) in DSM-5.", difficulty: 3, category: "Clinical Assessment", topic: "PTSD Diagnosis" },
  { id: "rp-623", stem: "When using the WHODAS 2.0, the therapist is assessing:", options: ["Disability and functional impairment across multiple life domains","Intelligence quotient","Personality traits","Substance use severity"], correctIndex: 0, rationale: "The WHODAS 2.0 (WHO Disability Assessment Schedule) measures functioning across six domains: cognition, mobility, self-care, getting along, life activities, and participation.", difficulty: 2, category: "Clinical Assessment", topic: "Functional Assessment" },
  { id: "rp-624", stem: "In solution-focused brief therapy, 'scaling questions' are used to:", options: ["Have clients rate their progress or confidence on a numerical scale to identify small changes","Measure the severity of psychiatric symptoms","Determine diagnostic severity levels","Assess the therapist's effectiveness"], correctIndex: 0, rationale: "Scaling questions (e.g., 'On a scale of 1-10, how confident are you?') help identify small changes, set goals, and measure progress in a client-centered way.", difficulty: 1, category: "Therapeutic Modalities", topic: "SFBT" },
  { id: "rp-625", stem: "Compassion fatigue in therapists is characterized by:", options: ["Emotional and physical exhaustion resulting from chronic exposure to clients' traumatic material","Lack of compassion for clients from the start of practice","Excessive personal involvement in clients' lives","A conscious decision to reduce empathy for self-protection"], correctIndex: 0, rationale: "Compassion fatigue (secondary traumatic stress) results from the cumulative emotional toll of working with traumatized clients. It differs from burnout, which relates to workplace conditions.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Self-Care" },
  { id: "rp-626", stem: "A therapist who shares their own recovery experience with a client to normalize the client's struggle is using:", options: ["Therapist self-disclosure","Interpretation","Free association","Systematic desensitization"], correctIndex: 0, rationale: "Strategic self-disclosure can normalize experiences and strengthen the alliance. It should be brief, purposeful, and in service of the client's treatment goals, not the therapist's needs.", difficulty: 1, category: "Therapeutic Modalities", topic: "Therapeutic Techniques" },
  { id: "rp-627", stem: "A client with conversion disorder (functional neurological symptom disorder) presents with paralysis of the left arm with no neurological explanation. The therapist should recognize that:", options: ["The symptoms are involuntary and not intentionally produced","The client is malingering for secondary gain","The symptoms will resolve spontaneously without intervention","Physical therapy alone is sufficient treatment"], correctIndex: 0, rationale: "Conversion disorder involves genuine, involuntary neurological symptoms without organic cause. Unlike malingering or factitious disorder, symptoms are not intentionally produced.", difficulty: 3, category: "Clinical Assessment", topic: "Somatic Disorders" },
  { id: "rp-628", stem: "According to Erikson's psychosocial development theory, the central conflict of adolescence is:", options: ["Identity vs. Role Confusion","Intimacy vs. Isolation","Industry vs. Inferiority","Generativity vs. Stagnation"], correctIndex: 0, rationale: "Erikson's fifth stage (adolescence, ages 12-18) involves developing a coherent sense of identity. Failure results in role confusion and difficulty committing to values, goals, and relationships.", difficulty: 1, category: "Clinical Assessment", topic: "Developmental Theory" },
  { id: "rp-629", stem: "Vicarious traumatization differs from compassion fatigue in that it specifically involves:", options: ["Lasting changes in the therapist's worldview, beliefs, and sense of safety","Temporary emotional exhaustion after difficult sessions","Physical symptoms like headaches and insomnia","Intentional boundary violations with clients"], correctIndex: 0, rationale: "Vicarious traumatization (Pearlman & Saakvitne) involves permanent shifts in the therapist's cognitive schemas about safety, trust, esteem, and control from cumulative exposure to trauma material.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Self-Care" },
  { id: "rp-630", stem: "In Cognitive Behavioral Therapy, a 'behavioral experiment' involves:", options: ["Testing the validity of a belief by collecting real-world evidence through planned activities","Conditioning a new behavioral response through reinforcement","An unethical research procedure on clients","Random assignment of clients to treatment conditions"], correctIndex: 0, rationale: "Behavioral experiments test automatic thoughts and beliefs by designing specific real-world activities to gather evidence. They are collaborative, hypothesis-driven interventions.", difficulty: 2, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-631", stem: "When working with an older adult client, the therapist should be particularly aware of:", options: ["The potential interaction between medical conditions, medications, and psychological symptoms","The assumption that depression is a normal part of aging","The ineffectiveness of psychotherapy for older adults","The need to always involve family in treatment decisions"], correctIndex: 0, rationale: "Older adults often have complex medical conditions and polypharmacy that can mimic or exacerbate psychological symptoms. Depression is not a normal part of aging and is treatable.", difficulty: 2, category: "Cultural Competence", topic: "Geriatric Considerations" },
  { id: "rp-632", stem: "A genogram in family therapy is used to:", options: ["Map multigenerational family patterns, relationships, and significant events","Measure genetic risk for mental illness","Record session attendance","Track medication compliance"], correctIndex: 0, rationale: "Genograms visually map family structure, relationships, patterns, and significant events across generations, helping identify recurring themes and intergenerational transmission of trauma.", difficulty: 1, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-633", stem: "The 'here-and-now' focus in group therapy involves:", options: ["Attending to what is happening between group members in the present moment","Practicing mindfulness meditation exercises","Discussing only current events in members' lives","Avoiding all discussion of the past"], correctIndex: 0, rationale: "The here-and-now (Yalom) focuses on interpersonal processes occurring within the group itself. It involves two tiers: experiencing the interaction and then reflecting on it.", difficulty: 2, category: "Group Therapy", topic: "Group Process" },
  { id: "rp-634", stem: "A therapist suspects a client may have an undiagnosed autism spectrum disorder. The most appropriate action is to:", options: ["Refer for comprehensive neuropsychological evaluation while continuing to provide supportive therapy","Diagnose the client based on clinical observation alone","Modify treatment approach without discussing concerns with the client","Discontinue therapy until a diagnosis is confirmed"], correctIndex: 0, rationale: "Suspected ASD warrants referral for specialized evaluation. The therapist should continue supportive therapy, discuss observations with the client, and potentially adapt their approach.", difficulty: 2, category: "Clinical Assessment", topic: "Neurodevelopmental Disorders" },
  { id: "rp-635", stem: "In mindfulness-based cognitive therapy (MBCT), the primary mechanism of change is:", options: ["Developing a decentered relationship with thoughts and feelings to prevent depressive relapse","Eliminating all negative thoughts through meditation","Achieving a state of permanent calm","Replacing negative thoughts with positive affirmations during meditation"], correctIndex: 0, rationale: "MBCT teaches decentering—observing thoughts as mental events rather than facts. This metacognitive awareness interrupts the ruminative patterns that trigger depressive relapse.", difficulty: 3, category: "Therapeutic Modalities", topic: "Mindfulness-Based Approaches" },
  { id: "rp-636", stem: "A client with avoidant personality disorder typically presents with:", options: ["Social inhibition, feelings of inadequacy, and hypersensitivity to negative evaluation","Grandiosity, need for admiration, and lack of empathy","Instability in relationships, self-image, and affect","Detachment from social relationships and restricted emotional expression"], correctIndex: 0, rationale: "Avoidant PD features social inhibition, feelings of inadequacy, and hypersensitivity to criticism. Unlike schizoid PD, these individuals desire relationships but fear rejection.", difficulty: 2, category: "Clinical Assessment", topic: "Personality Disorders" },
  { id: "rp-637", stem: "In a therapy group, a member consistently provides advice and caretaking to others while avoiding their own issues. The therapist should:", options: ["Gently explore this pattern in the group and invite the member to share their own experiences","Thank the member for being helpful and encourage more of this behavior","Allow the pattern to continue as it benefits other members","Remove the member from the group for not participating authentically"], correctIndex: 0, rationale: "The caretaker role can be a defense against vulnerability. Exploring this pattern therapeutically helps the member and models authenticity for the group.", difficulty: 3, category: "Group Therapy", topic: "Group Roles" },
  { id: "rp-638", stem: "Dialectical Behavior Therapy's 'DEAR MAN' skill is used for:", options: ["Making effective interpersonal requests while maintaining self-respect and the relationship","Managing acute suicidal crises","Regulating intense emotions through mindfulness","Tolerating distressing situations without acting impulsively"], correctIndex: 0, rationale: "DEAR MAN (Describe, Express, Assert, Reinforce, Mindful, Appear confident, Negotiate) is an interpersonal effectiveness skill for making requests or saying no effectively.", difficulty: 2, category: "Therapeutic Modalities", topic: "DBT" },
  { id: "rp-639", stem: "When assessing a client for dissociative identity disorder, a key diagnostic feature is:", options: ["Two or more distinct personality states with disruptions in sense of self and agency","Occasional forgetfulness about daily activities","Brief periods of daydreaming during sessions","Mood swings throughout the day"], correctIndex: 0, rationale: "DID involves two or more distinct personality states (alters) with disruptions in identity, consciousness, memory, perception, and behavior. It differs from normal variation in self-states.", difficulty: 3, category: "Clinical Assessment", topic: "Dissociative Disorders" },
  { id: "rp-640", stem: "The term 'therapeutic frame' refers to:", options: ["The consistent structure of therapy including time, setting, fees, and boundaries","The physical picture frames in the therapist's office","The theoretical framework guiding treatment","The client's perspective on their problems"], correctIndex: 0, rationale: "The therapeutic frame includes session time, frequency, location, fees, cancellation policies, and boundaries. A consistent frame provides safety and containment for therapeutic work.", difficulty: 1, category: "Ethics & Professional Practice", topic: "Therapeutic Boundaries" },
  { id: "rp-641", stem: "A therapist practicing from a feminist therapy perspective would emphasize:", options: ["The impact of societal power structures and gender socialization on the client's presenting problems","Strict therapeutic neutrality without social commentary","Biological determinism in understanding gender differences","Traditional gender roles as ideal therapeutic outcomes"], correctIndex: 0, rationale: "Feminist therapy examines how societal structures, power imbalances, and gender socialization contribute to psychological distress. It emphasizes empowerment and social justice.", difficulty: 2, category: "Therapeutic Modalities", topic: "Feminist Therapy" },
  { id: "rp-642", stem: "The GAD-7 questionnaire measures:", options: ["Generalized anxiety disorder symptom severity over the past two weeks","General adaptive functioning","Global assessment of dissociation","Group anxiety dynamics"], correctIndex: 0, rationale: "The GAD-7 is a 7-item self-report measure assessing anxiety severity. Scores: 0-4 minimal, 5-9 mild, 10-14 moderate, 15-21 severe anxiety.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-643", stem: "In relapse prevention therapy, 'apparently irrelevant decisions' (AIDs) refer to:", options: ["Seemingly minor decisions that gradually move the client closer to high-risk situations","Medical decisions unrelated to substance use","Decisions made by healthcare providers without client input","Treatment plan modifications made without documentation"], correctIndex: 0, rationale: "AIDs (Marlatt) are ostensibly insignificant choices that create a chain leading to relapse (e.g., driving past a bar 'because traffic is lighter'). Identifying AIDs helps prevent relapse.", difficulty: 3, category: "Therapeutic Modalities", topic: "Relapse Prevention" },
  { id: "rp-644", stem: "A therapist is working with a client who experienced childhood sexual abuse. The client reports no memories before age 8. This may be an example of:", options: ["Dissociative amnesia","Normal childhood amnesia","Repression confirming abuse occurred","Malingering"], correctIndex: 0, rationale: "While normal childhood amnesia typically covers ages before 3-4, extensive memory gaps through age 8 may suggest dissociative amnesia related to trauma. Careful assessment is needed.", difficulty: 3, category: "Clinical Assessment", topic: "Dissociative Disorders" },
  { id: "rp-645", stem: "In Bowen family systems theory, an 'emotional triangle' forms when:", options: ["A two-person system recruits a third person to manage anxiety and stabilize the relationship","Three family members share equal power in decision-making","A therapist joins a couple for family sessions","Three generations are present at a family gathering"], correctIndex: 0, rationale: "Triangulation occurs when a dyad under stress involves a third party to reduce anxiety. Bowen considered the triangle the basic building block of emotional systems.", difficulty: 3, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-646", stem: "A client with illness anxiety disorder (formerly hypochondriasis) primarily presents with:", options: ["Preoccupation with having or acquiring a serious illness despite minimal somatic symptoms","Fabricating symptoms for the sick role","Multiple unexplained physical symptoms causing significant distress","Deliberately producing symptoms for external incentives"], correctIndex: 0, rationale: "Illness anxiety disorder involves excessive worry about having a serious illness with minimal somatic symptoms. Somatic symptom disorder involves distressing somatic symptoms.", difficulty: 2, category: "Clinical Assessment", topic: "Somatic Disorders" },
  { id: "rp-647", stem: "The primary ethical concern with bartering for therapy services is:", options: ["The potential for exploitation and power imbalance inherent in the therapeutic relationship","It is always prohibited by all ethics codes","Bartering reduces the therapist's income","Insurance companies do not cover bartered services"], correctIndex: 0, rationale: "Bartering creates risk of exploitation due to the power differential. Some ethics codes allow it in limited circumstances (e.g., rural settings) with careful documentation and boundaries.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Financial Boundaries" },
  { id: "rp-648", stem: "A therapist trained only in individual therapy agrees to provide couples therapy. This violates which ethical principle?", options: ["Competence","Autonomy","Veracity","Fidelity"], correctIndex: 0, rationale: "Couples therapy requires specific training in relational dynamics, systemic thinking, and specialized interventions. Providing it without proper training violates the competence principle.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Scope of Practice" },
  { id: "rp-649", stem: "In group therapy, 'altruism' as a therapeutic factor refers to:", options: ["Members gaining a sense of value and purpose from helping other group members","The therapist's selfless dedication to the group","Financial generosity between group members","Volunteering in the community as a group activity"], correctIndex: 0, rationale: "Altruism (Yalom) occurs when members help each other, gaining self-worth and purpose. This is particularly powerful for clients who feel they have nothing to offer.", difficulty: 1, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "rp-650", stem: "A therapist using Prolonged Exposure therapy assigns 'in vivo exposure' homework. This involves:", options: ["Gradually approaching real-world situations the client has been avoiding due to trauma","Imagining traumatic scenes in the therapy session","Writing a detailed trauma narrative","Practicing relaxation techniques in feared situations"], correctIndex: 0, rationale: "In vivo exposure involves systematic, graduated approach to real-life situations that are safe but avoided due to trauma-related anxiety. It complements imaginal exposure done in session.", difficulty: 2, category: "Therapeutic Modalities", topic: "Trauma Therapy" },
  { id: "rp-651", stem: "The concept of 'emotional reasoning' as a cognitive distortion involves:", options: ["Assuming that feelings reflect reality (e.g., 'I feel stupid, so I must be stupid')","Using emotions to make rational decisions","Suppressing emotions to think clearly","Analyzing emotions in a journal"], correctIndex: 0, rationale: "Emotional reasoning is the belief that if one feels something, it must be true. This cognitive distortion is common in depression and anxiety and is targeted in CBT.", difficulty: 1, category: "Clinical Assessment", topic: "Cognitive Distortions" },
  { id: "rp-652", stem: "When a group therapist decides to add a new member to an ongoing group, they should:", options: ["Prepare both the new member and existing group members for the transition","Add the member without informing the group to avoid bias","Wait until a current member drops out","Only add members at the beginning of each calendar year"], correctIndex: 0, rationale: "Adding members affects group dynamics. Both the new member and existing group should be prepared. The new member needs orientation, and the group needs to process the change.", difficulty: 2, category: "Group Therapy", topic: "Group Management" },
  { id: "rp-653", stem: "A client reports hearing their name called when alone but no other auditory hallucinations. They are otherwise functioning well. This is most likely:", options: ["A hypnagogic or hypnopompic hallucination or isolated auditory experience within normal range","Active psychosis requiring antipsychotic medication","Dissociative identity disorder","Temporal lobe epilepsy"], correctIndex: 0, rationale: "Isolated experiences of hearing one's name called are common in the general population and do not necessarily indicate psychosis. Context, frequency, distress, and functioning determine clinical significance.", difficulty: 3, category: "Clinical Assessment", topic: "Differential Diagnosis" },
  { id: "rp-654", stem: "The concept of 'projective identification' in object relations theory involves:", options: ["Projecting an unwanted aspect of self onto another person and then interacting with them in ways that elicit the projected quality","Simple projection of unwanted feelings","Identifying with a role model's positive qualities","Using projective psychological testing"], correctIndex: 0, rationale: "Projective identification goes beyond projection—the projector unconsciously pressures the recipient to actually experience and enact the projected feelings, creating an interpersonal dynamic.", difficulty: 4, category: "Therapeutic Modalities", topic: "Object Relations" },
  { id: "rp-655", stem: "Cultural humility differs from cultural competence in that it:", options: ["Emphasizes an ongoing process of self-reflection and openness rather than achieving a fixed state of knowledge","Requires mastery of all cultural practices","Is only relevant for therapists from minority backgrounds","Involves learning about one culture in depth"], correctIndex: 0, rationale: "Cultural humility (Hook) is a lifelong process of self-reflection, recognizing power imbalances, and maintaining openness, rather than implying one can become 'competent' in another's culture.", difficulty: 2, category: "Cultural Competence", topic: "Cultural Humility" },
  { id: "rp-656", stem: "When working with a transgender client, the therapist should:", options: ["Use the client's affirmed name and pronouns and follow the client's lead on discussing gender identity","Require the client to discuss gender identity as the primary focus of therapy","Use the client's birth name until legal name change is complete","Avoid discussing gender identity to maintain neutrality"], correctIndex: 0, rationale: "Affirming the client's identity by using correct name/pronouns is essential. Gender identity may or may not be the presenting concern, and the therapist should follow the client's needs.", difficulty: 1, category: "Cultural Competence", topic: "Gender Identity" },
  { id: "rp-657", stem: "In crisis intervention, 'lethality assessment' specifically evaluates:", options: ["The immediacy and severity of danger to self or others","The client's overall personality functioning","Long-term suicide risk factors only","The client's capacity to engage in therapy"], correctIndex: 0, rationale: "Lethality assessment evaluates acute danger: current ideation, plan specificity, means access, intent, timeline, and protective factors. It guides immediate intervention decisions.", difficulty: 2, category: "Crisis Intervention", topic: "Risk Assessment" },
  { id: "rp-658", stem: "A therapist recognizes that a client's anxiety about their child's health is excessive and impairing. However, the client comes from a culture where intense parental vigilance is expected. The therapist should:", options: ["Explore the client's distress within their cultural context before applying diagnostic labels","Diagnose generalized anxiety disorder based on DSM-5 criteria alone","Dismiss the anxiety as culturally normal and not clinically significant","Impose Western standards of parenting anxiety as the benchmark"], correctIndex: 0, rationale: "Cultural context must inform clinical assessment. What appears excessive in one culture may be normative in another. The therapist explores whether the behavior causes distress and impairment within the client's own cultural framework.", difficulty: 3, category: "Cultural Competence", topic: "Cultural Assessment" },
  { id: "rp-659", stem: "Functional analysis in behavioral therapy identifies:", options: ["The antecedents, behaviors, and consequences maintaining a problematic pattern","Unconscious motivations for behavior","The developmental origins of personality traits","Genetic predispositions to mental illness"], correctIndex: 0, rationale: "Functional analysis (ABC model) examines what triggers behavior (antecedents), the behavior itself, and what maintains it (consequences). This informs targeted behavioral interventions.", difficulty: 2, category: "Therapeutic Modalities", topic: "Behavioral Therapy" },
  { id: "rp-660", stem: "A therapist receives a gift from a client at the end of successful treatment. The most appropriate response is to:", options: ["Accept if modest and culturally appropriate, while exploring the meaning of the gift with the client","Always refuse gifts regardless of circumstances","Accept expensive gifts to avoid hurting the client's feelings","Accept but do not discuss it to avoid making the client uncomfortable"], correctIndex: 0, rationale: "Gift-giving norms vary culturally. A modest, end-of-treatment gift may be appropriate to accept. The therapist should explore the meaning therapeutically and consider cultural context.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Boundaries" },
  { id: "rp-661", stem: "Polyvagal theory (Porges) describes the autonomic nervous system as having three hierarchical states:", options: ["Ventral vagal (social engagement), sympathetic (fight/flight), and dorsal vagal (freeze/shutdown)","Conscious, preconscious, and unconscious","Id, ego, and superego","Hyperarousal, optimal arousal, and hypoarousal"], correctIndex: 0, rationale: "Polyvagal theory describes a hierarchy: ventral vagal supports social engagement and calm, sympathetic activates for defense, and dorsal vagal causes immobilization or shutdown.", difficulty: 3, category: "Clinical Assessment", topic: "Neuroscience" },
  { id: "rp-662", stem: "In Narrative Therapy, 'unique outcomes' or 'sparkling moments' are:", options: ["Instances when the client acted in ways that contradict the dominant problem-saturated narrative","Unusual therapy techniques used by the therapist","Rare breakthroughs in long-term therapy","Moments of therapist self-disclosure"], correctIndex: 0, rationale: "Unique outcomes are exceptions to the problem story that demonstrate the client's competence and agency. They become the foundation for constructing alternative, preferred narratives.", difficulty: 2, category: "Therapeutic Modalities", topic: "Narrative Therapy" },
  { id: "rp-663", stem: "A therapist working with a mandated client should:", options: ["Clarify the limits of confidentiality, reporting requirements, and what the client can still control in the therapeutic process","Refuse to work with mandated clients due to ethical concerns","Treat the client identically to voluntary clients without addressing the mandate","Share all session content with the referring agency"], correctIndex: 0, rationale: "With mandated clients, transparency about reporting obligations, what is confidential, and what the client can control builds trust and engagement despite the coercive context.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Mandated Treatment" },
  { id: "rp-664", stem: "The 'abstinence violation effect' in relapse prevention describes:", options: ["The cognitive and emotional response to a lapse that can escalate it into a full relapse through guilt and loss of perceived control","Physical withdrawal symptoms after stopping substances","The therapist's insistence on complete abstinence","A legal consequence of violating probation terms"], correctIndex: 0, rationale: "The abstinence violation effect (Marlatt) occurs when a lapse triggers global attributions of failure, guilt, and loss of control, increasing the likelihood of continued use (full relapse).", difficulty: 3, category: "Therapeutic Modalities", topic: "Relapse Prevention" },
  { id: "rp-665", stem: "When a client expresses suicidal ideation, the first question a therapist should ask is:", options: ["Whether the client has a specific plan for how they would attempt suicide","How long they have been feeling this way","Whether they have a history of mental illness","What their childhood was like"], correctIndex: 0, rationale: "After identifying suicidal ideation, assessing for a specific plan helps determine acuity and lethality. Plan specificity, means access, and intent guide the level of intervention needed.", difficulty: 2, category: "Crisis Intervention", topic: "Suicide Assessment" },
  { id: "rp-666", stem: "The concept of 'therapeutic neutrality' in psychoanalytic therapy means:", options: ["Not imposing the therapist's values while maintaining curiosity about all aspects of the client's experience","Being emotionally cold and detached","Having no opinion about the client's behavior","Refusing to answer any client questions"], correctIndex: 0, rationale: "Therapeutic neutrality involves equidistant curiosity toward the client's id, ego, and superego. It does not mean coldness but rather non-judgmental exploration of all material.", difficulty: 3, category: "Therapeutic Modalities", topic: "Psychoanalytic Therapy" },
  { id: "rp-667", stem: "Which neurotransmitter system is most associated with the mechanism of action of SSRIs?", options: ["Serotonin","Dopamine","Norepinephrine","GABA"], correctIndex: 0, rationale: "SSRIs (Selective Serotonin Reuptake Inhibitors) block the reabsorption of serotonin, increasing its availability in the synaptic cleft. Understanding this helps therapists discuss medication with clients.", difficulty: 1, category: "Clinical Assessment", topic: "Psychopharmacology Awareness" },
  { id: "rp-668", stem: "In a process group, a therapist notices that members consistently avoid discussing a particular topic. This group-level phenomenon is called:", options: ["Group resistance","Social loafing","Deindividuation","Groupthink"], correctIndex: 0, rationale: "Group resistance occurs when the group collectively avoids threatening material. The therapist names the avoidance and explores what function it serves for the group.", difficulty: 3, category: "Group Therapy", topic: "Group Process" },
  { id: "rp-669", stem: "A therapist providing services to a client under a managed care plan has an ethical obligation to:", options: ["Advocate for necessary treatment even if it exceeds what the managed care plan authorizes","Only provide services that are pre-authorized regardless of clinical need","Avoid discussing coverage limitations with the client","Accept the managed care company's treatment decisions without question"], correctIndex: 0, rationale: "Therapists must advocate for clinically necessary treatment. If managed care denies needed services, the therapist should inform the client of options and pursue appeals.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Managed Care Ethics" },
  { id: "rp-670", stem: "In Emotion-Focused Therapy (EFT) for individuals, 'emotion coaching' involves:", options: ["Helping clients identify, experience, and transform maladaptive emotional responses","Teaching clients to suppress unwanted emotions","Instructing clients on the correct emotions to feel in each situation","Using cognitive techniques to override emotional experiences"], correctIndex: 0, rationale: "EFT emotion coaching helps clients approach, tolerate, and process emotions rather than avoid them. It involves accessing primary adaptive emotions that may be blocked by secondary emotions.", difficulty: 3, category: "Therapeutic Modalities", topic: "EFT" },
  { id: "rp-671", stem: "The CAGE questionnaire screens for:", options: ["Alcohol use problems using four yes/no questions","Cognitive impairment in elderly patients","Child abuse and neglect risk","Cardiovascular disease risk factors"], correctIndex: 0, rationale: "CAGE asks about Cutting down, Annoyance at criticism, Guilty feelings, and Eye-opener drinking. Two or more positive responses suggest problematic alcohol use warranting further assessment.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-672", stem: "When a therapist's personal values conflict with a client's lifestyle choices, the therapist should:", options: ["Examine their own biases in supervision and determine if they can provide competent, non-judgmental care","Impose their values as therapeutic guidance","Refuse to treat the client based on value differences","Subtly guide the client toward the therapist's values"], correctIndex: 0, rationale: "Therapists must recognize when personal values interfere with objectivity. Supervision and self-reflection help determine whether effective treatment is possible or referral is needed.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Values Conflicts" },
  { id: "rp-673", stem: "A client with agoraphobia would most benefit from:", options: ["Gradual in vivo exposure to feared situations combined with cognitive restructuring","Insight-oriented therapy focused on dream analysis","Unstructured group therapy","Medication management alone without psychotherapy"], correctIndex: 0, rationale: "CBT with graded in vivo exposure is the gold-standard treatment for agoraphobia. Gradual approach to feared situations, combined with cognitive techniques, produces the most lasting improvements.", difficulty: 2, category: "Therapeutic Modalities", topic: "Anxiety Treatment" },
  { id: "rp-674", stem: "In Yalom's model, 'existential factors' in group therapy include:", options: ["Recognizing that life is sometimes unfair and that ultimately one faces life alone","Learning social skills through group interaction","Receiving guidance from the therapist","Gaining information about one's condition"], correctIndex: 0, rationale: "Existential factors involve confronting fundamental realities: responsibility for one's life, mortality, isolation, and the absence of guaranteed meaning. Groups provide a context for this exploration.", difficulty: 3, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "rp-675", stem: "A therapist treating a client with panic disorder explains that bodily sensations are misinterpreted as dangerous. This psychoeducation aligns with which model?", options: ["Clark's cognitive model of panic","Classical conditioning model","Psychoanalytic conflict model","Attachment theory model"], correctIndex: 0, rationale: "Clark's cognitive model proposes that panic attacks result from catastrophic misinterpretation of benign bodily sensations (e.g., racing heart = heart attack). Psychoeducation about this cycle is central to CBT for panic.", difficulty: 3, category: "Therapeutic Modalities", topic: "CBT" },
  { id: "rp-676", stem: "When treating a client with body dysmorphic disorder, which therapeutic approach is most evidence-based?", options: ["CBT with exposure and response prevention targeting appearance-related compulsions","Cosmetic surgery referral","Reassurance-seeking accommodation","Psychoanalytic interpretation of body image distortions"], correctIndex: 0, rationale: "CBT with ERP is the first-line treatment for BDD. It targets compulsive checking, reassurance-seeking, and avoidance while challenging distorted beliefs about appearance.", difficulty: 3, category: "Therapeutic Modalities", topic: "OCD Spectrum Treatment" },
  { id: "rp-677", stem: "In family therapy, a 'parentified child' refers to:", options: ["A child who takes on adult caretaking responsibilities within the family system","A parent who acts childishly","A child who disobeys parents","A child placed in foster care"], correctIndex: 0, rationale: "Parentification occurs when a child assumes parental roles (emotional caretaking, managing siblings, household responsibilities), reversing the appropriate parent-child hierarchy.", difficulty: 2, category: "Therapeutic Modalities", topic: "Family Therapy" },
  { id: "rp-678", stem: "The ACE (Adverse Childhood Experiences) study demonstrated that:", options: ["Cumulative childhood adversity is strongly correlated with adult physical and mental health problems","Only severe childhood abuse leads to adult health problems","Childhood adversity has no measurable impact on adult health","Protective factors completely eliminate the effects of childhood adversity"], correctIndex: 0, rationale: "The ACE study (Felitti & Anda) showed a dose-response relationship between childhood adversity (abuse, neglect, household dysfunction) and adult disease, mental illness, and early death.", difficulty: 2, category: "Clinical Assessment", topic: "Developmental Trauma" },
  { id: "rp-679", stem: "When a client requests access to their therapy records, the therapist should:", options: ["Provide access in accordance with applicable laws while considering potential harm from certain content","Refuse all requests to protect confidentiality","Provide unedited notes including the therapist's personal reflections","Require a court order before releasing any records"], correctIndex: 0, rationale: "Clients generally have a right to access their records. The therapist provides access per HIPAA/state law but may withhold information that could cause substantial harm.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Record Access" },
  { id: "rp-680", stem: "Transference-focused psychotherapy (TFP) is primarily designed for:", options: ["Borderline personality disorder","Major depressive disorder","Generalized anxiety disorder","Autism spectrum disorder"], correctIndex: 0, rationale: "TFP (Kernberg) uses the analysis of transference patterns to address identity diffusion and primitive defenses in BPD, promoting integration of split self and object representations.", difficulty: 3, category: "Therapeutic Modalities", topic: "Personality Disorder Treatment" },
  { id: "rp-681", stem: "A therapist observes that a client uses humor excessively to deflect from painful emotions. In terms of defense mechanisms, this represents:", options: ["A mature defense that may become maladaptive when used to avoid necessary emotional processing","A psychotic-level defense requiring immediate intervention","Normal social behavior with no clinical significance","An immature defense indicating personality pathology"], correctIndex: 0, rationale: "Humor is generally classified as a mature defense. However, when used consistently to avoid emotional engagement, it warrants gentle exploration of what the humor may be protecting.", difficulty: 3, category: "Clinical Assessment", topic: "Defense Mechanisms" },
  { id: "rp-682", stem: "In CBT for insomnia (CBT-I), stimulus control involves:", options: ["Using the bed only for sleep and intimacy, leaving the bed if unable to sleep within 15-20 minutes","Taking sleep medication at the same time each night","Spending more time in bed to increase sleep opportunity","Exercising vigorously right before bedtime"], correctIndex: 0, rationale: "Stimulus control reassociates the bed with sleep by restricting bed activities and requiring the person to get up if not sleeping. CBT-I is the first-line treatment for chronic insomnia.", difficulty: 2, category: "Therapeutic Modalities", topic: "Behavioral Interventions" },
  { id: "rp-683", stem: "The concept of 'moral injury' differs from PTSD in that it primarily involves:", options: ["Profound guilt, shame, or betrayal from events that violate one's moral code","Re-experiencing traumatic events through flashbacks","Exaggerated startle response and hypervigilance","Avoidance of trauma-related stimuli"], correctIndex: 0, rationale: "Moral injury (Litz) results from perpetrating, failing to prevent, or witnessing events that transgress deeply held moral beliefs. It features guilt, shame, and existential crisis rather than fear-based symptoms.", difficulty: 3, category: "Clinical Assessment", topic: "Trauma Subtypes" },
  { id: "rp-684", stem: "In a therapy group that has been meeting for several months, two members begin a romantic relationship. The therapist should:", options: ["Address the situation in the group, exploring its impact on group dynamics and the individuals' therapy","Ignore the relationship as it occurs outside the group","Immediately remove both members from the group","Encourage the relationship as it demonstrates improved social skills"], correctIndex: 0, rationale: "Romantic relationships between members affect group dynamics, confidentiality, and therapeutic work. The therapist addresses it openly, exploring implications while maintaining group safety.", difficulty: 3, category: "Group Therapy", topic: "Group Boundaries" },
  { id: "rp-685", stem: "Cognitive remediation therapy is primarily used for:", options: ["Improving cognitive functioning in clients with schizophrenia or other conditions with cognitive deficits","Treating specific phobias","Managing chronic pain","Reducing substance use cravings"], correctIndex: 0, rationale: "Cognitive remediation targets neurocognitive deficits (attention, memory, executive function) common in schizophrenia and other conditions, using structured exercises and strategy training.", difficulty: 3, category: "Therapeutic Modalities", topic: "Psychosis Treatment" },
  { id: "rp-686", stem: "When working with a client who has intellectual disability, the therapist should:", options: ["Adapt therapeutic approaches to the client's cognitive level while respecting their autonomy and dignity","Assume the client cannot benefit from psychotherapy","Only work with the client's caregivers rather than the client directly","Use the same approaches without any modifications"], correctIndex: 0, rationale: "Clients with intellectual disabilities can benefit from adapted psychotherapy. Adaptations include simpler language, concrete examples, visual aids, and shorter sessions while respecting client dignity.", difficulty: 2, category: "Cultural Competence", topic: "Disability Considerations" },
  { id: "rp-687", stem: "The SASRQ (Stanford Acute Stress Reaction Questionnaire) is used to assess:", options: ["Acute stress disorder symptoms following a traumatic event","Seasonal affective disorder severity","Social anxiety in school settings","Substance abuse relapse risk"], correctIndex: 0, rationale: "The SASRQ measures acute stress reactions including dissociation, re-experiencing, avoidance, anxiety, and impaired functioning in the first month following trauma.", difficulty: 3, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-688", stem: "A therapist who practices 'deliberate practice' in their professional development:", options: ["Systematically works on specific clinical skills through targeted exercises with feedback","Simply accumulates years of clinical experience","Reads professional literature without applying it clinically","Attends continuing education workshops passively"], correctIndex: 0, rationale: "Deliberate practice (Ericsson; applied to therapy by Rousmaniere) involves intentionally practicing specific skills at the edge of one's ability with feedback, going beyond passive experience.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Professional Development" },
  { id: "rp-689", stem: "A client describes feeling simultaneously drawn to and repelled by their therapist. From an object relations perspective, this represents:", options: ["Ambivalence rooted in early attachment experiences with inconsistent caregivers","A sign that therapy should be terminated","Normal therapeutic boundaries being maintained","The client's conscious manipulation of the therapist"], correctIndex: 0, rationale: "Ambivalence toward the therapist often mirrors early relational patterns with inconsistent caregivers. Object relations theory views this as clinically meaningful transference to be explored.", difficulty: 3, category: "Therapeutic Modalities", topic: "Object Relations" },
  { id: "rp-690", stem: "In trauma therapy, the concept of 'titration' refers to:", options: ["Carefully managing the pace and intensity of trauma exposure to prevent overwhelming the client","Adjusting medication dosages for psychiatric symptoms","The gradual increase of session frequency over time","Measuring client progress through standardized assessments"], correctIndex: 0, rationale: "Titration (from Somatic Experiencing) involves carefully dosing the amount of traumatic material processed to keep the client within their window of tolerance, preventing retraumatization.", difficulty: 3, category: "Therapeutic Modalities", topic: "Trauma Therapy" },
  { id: "rp-691", stem: "A client with dependent personality disorder is likely to present in therapy by:", options: ["Seeking excessive reassurance and having difficulty making decisions without the therapist's input","Refusing to engage in the therapeutic process","Dominating sessions with grandiose self-narratives","Expressing paranoid suspicion about the therapist's motives"], correctIndex: 0, rationale: "Dependent PD features excessive need to be taken care of, submissive behavior, and difficulty making independent decisions. In therapy, this manifests as reliance on the therapist for direction.", difficulty: 2, category: "Clinical Assessment", topic: "Personality Disorders" },
  { id: "rp-692", stem: "Collaborative safety planning differs from a 'no-suicide contract' in that:", options: ["It is an evidence-based, active coping strategy rather than a passive agreement","It requires the client's signature on a legal document","It is only used in inpatient settings","It eliminates all suicide risk"], correctIndex: 0, rationale: "Safety planning (Stanley & Brown) is evidence-based and involves active strategies the client can use during crises. No-suicide contracts lack evidence, create false security, and may impede honest disclosure.", difficulty: 3, category: "Crisis Intervention", topic: "Safety Planning" },
  { id: "rp-693", stem: "When using the BDI-II (Beck Depression Inventory-II), a score of 29 indicates:", options: ["Severe depression","Minimal depression","Mild depression","Moderate depression"], correctIndex: 0, rationale: "BDI-II scoring: 0-13 minimal, 14-19 mild, 20-28 moderate, 29-63 severe depression. A score of 29 falls in the severe range.", difficulty: 1, category: "Clinical Assessment", topic: "Screening Tools" },
  { id: "rp-694", stem: "A therapist working from a strengths-based perspective would:", options: ["Identify and build upon the client's existing resources, abilities, and resilience","Focus exclusively on diagnosing pathology","Minimize the client's problems to maintain positivity","Avoid discussing difficulties to prevent discouragement"], correctIndex: 0, rationale: "Strengths-based practice emphasizes client resources and resilience while still acknowledging difficulties. It builds on what the client does well rather than focusing solely on deficits.", difficulty: 1, category: "Therapeutic Modalities", topic: "Strengths-Based Approach" },
  { id: "rp-695", stem: "Sensorimotor Psychotherapy integrates:", options: ["Body-based interventions with cognitive and emotional processing for trauma treatment","Only cognitive techniques without attention to the body","Exclusively pharmacological approaches","Traditional psychoanalysis without modification"], correctIndex: 0, rationale: "Sensorimotor Psychotherapy (Ogden) integrates somatic interventions with cognitive and emotional processing, addressing how trauma is held in the body through posture, movement, and sensation.", difficulty: 3, category: "Therapeutic Modalities", topic: "Somatic Therapy" },
  { id: "rp-696", stem: "In group therapy, the 'corrective emotional experience' (Alexander) occurs when:", options: ["A group member has a new, healthier relational experience that differs from past harmful patterns","The therapist corrects a member's factual misunderstanding","A member receives feedback about their behavior from the group","The group follows a corrective protocol after a norm violation"], correctIndex: 0, rationale: "The corrective emotional experience occurs when the group provides responses different from those in the member's problematic relational patterns, creating new relational templates.", difficulty: 3, category: "Group Therapy", topic: "Therapeutic Factors" },
  { id: "rp-697", stem: "A therapist finds that a former client (therapy ended 2 years ago) has applied for a job at the therapist's practice. The therapist should:", options: ["Recuse themselves from the hiring process and consult about the ethical implications","Hire the former client based on qualifications alone","Reject the application without explanation","Interview the former client as if there were no prior relationship"], correctIndex: 0, rationale: "A supervisory/employment relationship with a former client creates problematic power dynamics. The therapist should recuse from hiring decisions and consult about potential boundary concerns.", difficulty: 3, category: "Ethics & Professional Practice", topic: "Post-Termination Relationships" },
  { id: "rp-698", stem: "Psychoeducation about the fight-flight-freeze response is most useful for clients with:", options: ["Trauma and anxiety disorders to normalize their physiological responses","Intellectual disabilities to improve cognitive functioning","Eating disorders to understand caloric needs","Personality disorders to explain their interpersonal patterns"], correctIndex: 0, rationale: "Understanding the fight-flight-freeze response helps trauma and anxiety clients normalize their symptoms, reduce self-blame, and engage more effectively in treatment.", difficulty: 1, category: "Therapeutic Modalities", topic: "Psychoeducation" },
  { id: "rp-699", stem: "A client's protective factors against suicide include:", options: ["Strong social connections, reasons for living, and access to mental health treatment","Previous suicide attempts","Family history of suicide","Current substance use"], correctIndex: 0, rationale: "Protective factors include social connectedness, sense of purpose, responsibility to family, religious beliefs, coping skills, and access to effective treatment. They buffer against risk factors.", difficulty: 1, category: "Crisis Intervention", topic: "Suicide Protection" },
  { id: "rp-700", stem: "In the termination phase of therapy, the therapist should:", options: ["Review progress, consolidate gains, plan for maintenance, and process the ending of the relationship","End abruptly to promote client independence","Avoid discussing the therapeutic relationship to prevent dependency","Continue treatment indefinitely to prevent relapse"], correctIndex: 0, rationale: "Effective termination reviews progress, consolidates skills, anticipates future challenges, develops a maintenance plan, and processes the meaning of the therapeutic relationship ending.", difficulty: 2, category: "Ethics & Professional Practice", topic: "Termination" }
];
